// // This module compares two 4-bit inputs and determines if a is greater than or equal to b.
module comparator_4bit (
    input [3:0] a,
    input [3:0] b,
    output less,
    output equal,
    output greater
);

assign less = (a < b);
assign equal = (a == b);
assign greater = (a > b);

endmodule
